package github.chains;

import spoon.processing.AbstractProcessor;
import spoon.reflect.declaration.CtImport;
import spoon.reflect.declaration.CtType;
import spoon.reflect.factory.Factory;
import spoon.reflect.reference.CtTypeReference;

import java.util.List;

/**
 * Generic processor to fix Jakarta Interceptor API migration from javax.interceptor to jakarta.interceptor
 * This transformation addresses the breaking change in Jakarta EE 9+ where packages were renamed
 */
public class JakartaInterceptorMigrationProcessor extends AbstractProcessor<CtType<?>> {

    @Override
    public void process(CtType<?> ctType) {
        Factory factory = ctType.getFactory();

        // Process all imports to replace javax.interceptor with jakarta.interceptor
        List<CtImport> imports = ctType.getImports();
        for (CtImport ctImport : imports) {
            if (ctImport.getReference() != null) {
                String importFqcn = ctImport.getReference().getQualifiedName();
                if (importFqcn.startsWith("javax.interceptor")) {
                    // Create new import with jakarta.interceptor
                    String newImport = importFqcn.replace("javax.interceptor", "jakarta.interceptor");
                    CtImport newImportStmt = factory.createImport(factory.Type().createReference(newImport));
                    ctImport.replace(newImportStmt);
                }
            }
        }

        // Process type references in the code
        ctType.filterChildren((CtTypeReference<?> reference) -> {
            String qualifiedName = reference.getQualifiedName();
            if (qualifiedName.startsWith("javax.interceptor")) {
                // Replace the reference with jakarta.interceptor equivalent
                String newQualifiedName = qualifiedName.replace("javax.interceptor", "jakarta.interceptor");
                reference.setQualifiedName(newQualifiedName);
            }
            return false;
        }).forEach(reference -> {});
    }
}

